31	       
32	        func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
33	            let rawMax = alarmLevel.offScale ?? radiationType.defaultMaxValue
34	
35	            func step(for value: Decimal) -> Decimal {
36	                var step = minStep
37	                var threshold = switchAt
38	
39	                while value >= threshold * 10 {
40	                    step *= 10
41	                    threshold *= 10
42	                }
43	
44	                return step
45	            }
46	
47	            let topStep = step(for: rawMax)
48	            var ceiled = Decimal()
49	            var divided = rawMax / topStep
50	            NSDecimalRound(&ceiled, &divided, 0, .up)
51	            let maxValue = ceiled * topStep
52	            
53	            var values: [Decimal] = []
54	            var value = maxValue
55	
56	            while value > 0 {
57	                values.append(value)
58	                let currentStep = step(for: value)
59	                let next = value - currentStep
60	                let nextStep = next > 0 ? step(for: next) : minStep
61	
62	                if nextStep < currentStep {
63	                    value = value - nextStep
64	                } else {
65	                    value = next <= 0 ? 0 : next
66	                }
67	            }
68	            values.append(0)
69	
70	            return values
71	        }
72	        
73	        let values: [Decimal] = {
74	            switch radiationType {
75	            case .radiationLevel(let level):
76	                switch level {
77	                case .countRate:
78	                    makeValues(minStep: 0.1, switchAt: 20)
79	
80	                case .doseRate:
81	                    makeValues(minStep: 0.01, switchAt: 2)
82	                }
83	
84	            case .dose:
