32	    
33	     func areFloatArraysNearlyEqual(_ array: [Float]) -> Bool {
34	        guard self.count == array.count else {
35	            return false
36	        }
37	        
38	        for (index, value) in self.enumerated() {
39	            if !value.isNearlyEqual(to: array[index]) {
40	                return false
